#!/bin/bash\n# Script 2: Deploy Services - Corrected\n\nset -euo pipefail\n\n# --- Colors ---\nRED=\'\\033[0;31m\'\nGREEN=\'\\033[0;32m\'\nYELLOW=\'\\033[1;33m\'\nCYAN=\'\\033[0;36m\'\nNC=\'\\033[0m\'\n\n# --- Logging (Early init) ---\nlog()  { echo -e \"${GREEN}[$(date +\'%H:%M:%S\')]${NC} $1\"; }\nwarn() { echo -e \"${YELLOW}[$(date +\'%H:%M:%S\')]${NC} $1\"; }\nerror(){ echo -e \"${RED}[$(date +\'%H:%M:%S\')]${NC} $1\"; }\n\n# --- Find and Load Environment ---\nENV_FILE=$(find /mnt/data -name \".env\" -printf \"%T@ %p\\n\" | sort -n | tail -1 | cut -d\' \' -f2-)\nif [[ -z \"${ENV_FILE}\" ]]; then\n    error \"Could not find a .env file in /mnt/data. Run script 1 first.\"\n    exit 1\nfi\nsource \"${ENV_FILE}\"\n\n# --- Structured Logging Setup ---\nLOG_DIR=\"${DATA_ROOT}/logs\"\nmkdir -p \"${LOG_DIR}\"\nchown \"${TENANT_UID}:${TENANT_GID}\" \"${LOG_DIR}\"\nLOG_FILE=\"${LOG_DIR}/script-2-$(date +%Y%m%d-%H%M%S).log\"\nexec > >(tee -a \"${LOG_FILE}\") 2>&1\n\nlog \"======= AI Platform Deployment Starting =======\"\nlog \"Using environment file: ${ENV_FILE}\"\nlog \"Logging to: ${LOG_FILE}\"\n\n# --- Key Variables ---\nCOMPOSE_FILE=\"${DATA_ROOT}/docker-compose.yml\"\n\n# --- Docker Check ---\nif ! docker info &>/dev/null; then\n    error \"Docker is not running. Please start Docker and try again.\"\n    exit 1\nfi\nlog \"Docker is active.\"\n\n# --- Build docker-compose.yml ---\nlog \"Generating docker-compose.yml...\"\n\n# Start with header and network. NO version attribute.\ncat > \"${COMPOSE_FILE}\" << EOF\n# Auto-generated by deployment script\nservices:\nEOF\n\n# --- Service Definitions ---\nif [[ \"${ENABLE_POSTGRES}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  postgres:\n    image: postgres:15-alpine\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    environment:\n      POSTGRES_USER: \${POSTGRES_USER}\n      POSTGRES_PASSWORD: \${POSTGRES_PASSWORD}\n      POSTGRES_DB: \${POSTGRES_DB}\n    volumes:\n      - ${DATA_ROOT}/postgres:/var/lib/postgresql/data\nEOF\nfi\n\nif [[ \"${ENABLE_REDIS}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  redis:\n    image: redis:7-alpine\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    command: redis-server --requirepass \${REDIS_PASSWORD}\n    volumes:\n      - ${DATA_ROOT}/redis:/data\nEOF\nfi\n\n# CORRECTED Caddy Service Definition\nif [[ \"${ENABLE_CADDY}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  caddy:\n    image: caddy:2-alpine\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"80:80\"\n      - \"443:443\"\n    volumes:\n      - ${DATA_ROOT}/caddy/Caddyfile:/etc/caddy/Caddyfile\n      - ${DATA_ROOT}/caddy/data:/data\n      - ${DATA_ROOT}/caddy/config:/config\nEOF\nfi\n\nif [[ \"${ENABLE_OLLAMA}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  ollama:\n    image: ollama/ollama\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"11434:11434\"\n    volumes:\n      - ${DATA_ROOT}/ollama:/root/.ollama\n    $([ \"${GPU_TYPE}\" == \"nvidia\" ] && echo -e \"deploy:\\n      resources:\\n        reservations:\\n          devices:\\n            - driver: nvidia\\n              count: all\\n              capabilities: [gpu]\")\nEOF\nfi\n\nif [[ \"${ENABLE_QDRANT}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  qdrant:\n    image: qdrant/qdrant:latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"6333:6333\"\n    environment:\n      QDRANT__SERVICE__API_KEY: \${QDRANT_API_KEY}\n    volumes:\n      - ${DATA_ROOT}/qdrant:/qdrant/storage\nEOF\nfi\n\nif [[ \"${ENABLE_OPENWEBUI}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  openwebui:\n    image: ghcr.io/open-webui/open-webui:main\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"8080:8080\"\n    environment:\n      OLLAMA_BASE_URL: \${OLLAMA_INTERNAL_URL}\n    depends_on:\n      - ollama\nEOF\nfi\n\nif [[ \"${ENABLE_N8N}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  n8n:\n    image: n8nio/n8n:latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"5678:5678\"\n    environment:\n      DB_TYPE: postgres\n      DB_POSTGRESDB_HOST: postgres\n      DB_POSTGRESDB_DATABASE: \${POSTGRES_DB}\n      DB_POSTGRESDB_USER: \${POSTGRES_USER}\n      DB_POSTGRESDB_PASSWORD: \${POSTGRES_PASSWORD}\n      N8N_ENCRYPTION_KEY: \${N8N_ENCRYPTION_KEY}\n      N8N_BASIC_AUTH_ACTIVE: \"true\"\n      N8N_BASIC_AUTH_USER: \${N8N_USER}\n      N8N_PASSWORD: \${N8N_USER}\n    volumes:\n      - ${DATA_ROOT}/n8n:/home/node/.n8n\n    depends_on:\n      - postgres\nEOF\nfi\n\nif [[ \"${ENABLE_FLOWISE}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  flowise:\n    image: flowiseai/flowise:latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"3000:3000\"\n    environment:\n      DATABASE_TYPE: postgres\n      POSTGRES_HOST: postgres\n      POSTGRES_DATABASE: \${POSTGRES_DB}\n      POSTGRES_USER: \${POSTGRES_USER}\n      POSTGRES_PASSWORD: \${POSTGRES_PASSWORD}\n      FLOWISE_USERNAME: \${FLOWISE_USERNAME}\n      FLOWISE_PASSWORD: \${FLOWISE_PASSWORD}\n    volumes:\n      - ${DATA_ROOT}/flowise:/root/.flowise\n    depends_on:\n      - postgres\nEOF\nfi\n\nif [[ \"${ENABLE_ANYTHINGLLM}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  anythingllm:\n    image: mintplexlabs/anythingllm:latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"3001:3001\"\n    environment:\n      VECTOR_DB: \${VECTOR_DB}\n      QDRANT_ENDPOINT: \${QDRANT_INTERNAL_URL}\n      QDRANT_API_KEY: \${QDRANT_API_KEY}\n      OLLAMA_BASE_URL: \${OLLAMA_INTERNAL_URL}\n    volumes:\n      - ${DATA_ROOT}/anythingllm:/app/server/storage\n    depends_on:\n      - ollama\n      - qdrant\nEOF\nfi\n\nif [[ \"${ENABLE_LITELLM}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  litellm:\n    image: ghcr.io/berriai/litellm:main-latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"4000:4000\"\n    environment:\n      LITELLM_MASTER_KEY: \${LITELLM_MASTER_KEY}\nEOF\nfi\n\nif [[ \"${ENABLE_PROMETHEUS}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  prometheus:\n    image: prom/prometheus:latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"9090:9090\"\n    volumes:\n      - ${DATA_ROOT}/prometheus/prometheus.yml:/etc/prometheus/prometheus.yml\n      - ${DATA_ROOT}/prometheus_data:/prometheus\nEOF\nfi\n\nif [[ \"${ENABLE_GRAFANA}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  grafana:\n    image: grafana/grafana:latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"3000:3000\"\n    environment:\n      GF_SECURITY_ADMIN_USER: admin\n      GF_SECURITY_ADMIN_PASSWORD: \${GRAFANA_PASSWORD}\n    volumes:\n      - ${DATA_ROOT}/grafana:/var/lib/grafana\nEOF\nfi\n\nif [[ \"${ENABLE_AUTHENTIK}\" == \"true\" ]]; then\ncat >> \"${COMPOSE_FILE}\" << EOF\n  authentik:\n    image: ghcr.io/goauthentik/server:latest\n    restart: unless-stopped\n    networks: [\"${DOCKER_NETWORK}\"]\n    ports:\n      - \"9000:9000\"\n      - \"9443:9443\"\n    environment:\n      AUTHENTIK_SECRET_KEY: \${AUTHENTIK_SECRET_KEY}\n      AUTHENTIK_BOOTSTRAP_PASSWORD: \${AUTHENTIK_BOOTSTRAP_PASSWORD}\n      AUTHENTIK_POSTGRESQL__HOST: postgres\n      AUTHENTIK_POSTGRESQL__USER: \${POSTGRES_USER}\n      AUTHENTIK_POSTGRESQL__NAME: \${POSTGRES_DB}\n      AUTHENTIK_POSTGRESQL__PASSWORD: \${POSTGRES_PASSWORD}\n      AUTHENTIK_REDIS__HOST: redis\n      AUTHENTIK_REDIS__PASSWORD: \${REDIS_PASSWORD}\n    volumes:\n      - ${DATA_ROOT}/authentik/media:/media\n      - ${DATA_ROOT}/authentik/templates:/templates\n    depends_on:\n      - postgres\n      - redis\nEOF\nfi\n\n# --- Add Network Definition ---\ncat >> \"${COMPOSE_FILE}\" << EOF\n\nnetworks:\n  ${DOCKER_NETWORK}:\n    driver: bridge\nEOF\n\nlog \"docker-compose.yml generated successfully.\"\n\n# --- Deploy ---\nlog \"Deploying stack with Docker Compose...\"\ncd \"${DATA_ROOT}\"\ndocker compose -p \"${COMPOSE_PROJECT_NAME}\" up -d\ncd -\n\nlog \"Deployment initiated. Waiting for services to stabilize...\"\nsleep 60\n\nlog \"======= Deployment Complete =======\"\nlog \"Run \\\"sudo bash scripts/3-configure-services.sh\\\" to finalize setup.\"\n